SELECT DATASET_ID AS "datasetId", MAX(DATASET_NAME) AS "datasetName", MAX(OWNER_ACTOR_ID) AS "ownerActorId", MAX(LCI_MAJOR_CODE) AS "lciMajorCode", MAX(LCI_MAJOR_LABEL) AS "lciMajorLabel", MAX(LCI_MIDDLE_CODE) AS "lciMiddleCode", MAX(LCI_MIDDLE_LABEL) AS "lciMiddleLabel", MAX(LCI_SMALL_CODE) AS "lciSmallCode", MAX(LCI_SMALL_LABEL) AS "lciSmallLabel", MAX(SOURCE_FILE_NM) AS "sourceFileName", MAX(CASE_STATUS) AS "caseStatus", COUNT(*) AS "sectionCount", COALESCE(SUM(ROW_COUNT), 0) AS "rowCount", TO_CHAR(MAX(LAST_SAVED_AT), 'YYYY-MM-DD HH24:MI:SS') AS "savedAt" FROM ADMIN_EMISSION_SURVEY_CASE WHERE OWNER_ACTOR_ID = #{ownerActorId} AND DATASET_ID IS NOT NULL AND DATASET_ID <> ''
AND LCI_MAJOR_CODE = #{lciMajorCode}
AND LCI_MIDDLE_CODE = #{lciMiddleCode}
AND LCI_SMALL_CODE = #{lciSmallCode}
GROUP BY DATASET_ID ORDER BY MAX(LAST_SAVED_AT) DESC

SELECT LOG_ID AS "logId", DATASET_ID AS "datasetId", OWNER_ACTOR_ID AS "ownerActorId", SOURCE_FILE_NM AS "sourceFileName", LCI_MAJOR_CODE AS "lciMajorCode", LCI_MAJOR_LABEL AS "lciMajorLabel", LCI_MIDDLE_CODE AS "lciMiddleCode", LCI_MIDDLE_LABEL AS "lciMiddleLabel", LCI_SMALL_CODE AS "lciSmallCode", LCI_SMALL_LABEL AS "lciSmallLabel", RESULT_STATUS AS "resultStatus", MESSAGE AS "message", SECTION_COUNT AS "sectionCount", ROW_COUNT AS "rowCount", STORAGE_MODE AS "storageMode", SECTION_RESULT_JSON AS "sectionResultJson", TO_CHAR(UPLOADED_AT, 'YYYY-MM-DD HH24:MI:SS') AS "uploadedAt" FROM ADMIN_EMISSION_SURVEY_UPLOAD_LOG WHERE OWNER_ACTOR_ID = #{ownerActorId}
AND LCI_MAJOR_CODE = #{lciMajorCode}
AND LCI_MIDDLE_CODE = #{lciMiddleCode}
AND LCI_SMALL_CODE = #{lciSmallCode}
AND RESULT_STATUS = #{status}
ORDER BY UPLOADED_AT DESC

